import {
  Bird,
  Brain,
  BrickWall,
  Bug,
  CalendarCheck,
  Camera,
  Circle,
  Code2,
  Crosshair,
  FilePenLine,
  FileSearch,
  FlaskConical,
  Footprints,
  Gamepad2,
  Gift,
  Hourglass,
  Joystick,
  MessageCircleQuestion,
  Mountain,
  Palette,
  PartyPopper,
  PencilRuler,
  Puzzle,
  RefreshCcw,
  Rocket,
  SlidersHorizontal,
  Sparkles,
  TimerOff,
  TriangleAlert,
  Undo2,
  Worm,
  Wrench,
  type LucideIcon,
} from "lucide-react";

/**
 * Resolves the icon *names* stored in tokens (GENRE_HUES / STEP_META /
 * ACTIVITY_KIND_META / CREDIT_KIND_META) to lucide components. Tokens stay
 * dependency-free; components import this.
 */
const ICONS: Record<string, LucideIcon> = {
  Bird,
  Brain,
  BrickWall,
  Bug,
  CalendarCheck,
  Camera,
  Circle,
  Code2,
  Crosshair,
  FilePenLine,
  FileSearch,
  FlaskConical,
  Footprints,
  Gamepad2,
  Gift,
  Hourglass,
  Joystick,
  MessageCircleQuestion,
  Mountain,
  Palette,
  PartyPopper,
  PencilRuler,
  Puzzle,
  RefreshCcw,
  Rocket,
  SlidersHorizontal,
  Sparkles,
  TimerOff,
  TriangleAlert,
  Undo2,
  Worm,
  Wrench,
};

export function resolveIcon(name: string): LucideIcon {
  return ICONS[name] ?? Circle;
}
